import { useState,useEffect } from "react";
import {Link} from 'react-router-dom';
import axios from 'axios';
import jwt_decode from "jwt-decode";
export default function Utilisateur(){
    const [users,setUsers] = useState([]);
    const [infos,setInfos] = useState([]);
    const token = localStorage.getItem("token");
  
let role = null;

if(token){
    const decoded = jwtDecode(token);
    role = decoded.role; // "admin" ولا "user"
}
    const [username,setUsername] = useState('');
    const getUsers = async () => {
        const res = await axios.get('http://localhost:3001/users', {
          headers: { Authorization: `Bearer ${token}`}
        });
        setUsers(res.data);
    }
    useEffect(() => {
        getUsers();
    },[]);
    const nas = infos.length > 0 ? infos : users;
  
    return (
        <>
            {r === "admin" && (
                <Link to='/AjouterUtilisateur'>Ajouter un utilisateur</Link>
            )}
                <input type="text" value={username} onChange={(e) => setUsername(e.target.value)}/>
                    <button disabled={!username.trim()} onClick={async() => {
                    if (!username.trim()) {
                    setInfos([]);
                    return;
                    }
                    const res = await axios.get(`http://localhost:3001/searchUsername/${username}`, {
                    headers: { Authorization: `Bearer ${token}`}
                    });
                    setInfos(res.data);
                }}>search</button>
            <center>
                <table border='1'>
                <tr>
                    <th>name</th>
                    <th>email</th>
                    <th>role</th>
                    <th>actions</th>
                    <th>block/unblock</th>
                </tr>
                {nas.map((u,i) => (
                    <tr key={i}>
                        <td>{u.username}</td>
                        <td>{u.email}</td>
                        <td>{u.role}</td>
                        <td>
                           {u.role === "admin" && (
                             <button onClick={ async () => {
                                await axios.delete(`http://localhost:3001/delete/${u._id}`,{
                                headers: { Authorization: `Bearer ${token}` }
                                })
                                setUsers(prev => prev.filter(user => user._id !== u._id));
                            }}>supprimer</button>
                           )}
                            <Link to={`/modifierUtilisateur/${u._id}`}>modifier</Link>             
                            </td>
                            <td>
                                <center>
                                    <button onClick={ async ()=> {
                                    if(u.isBlocked){
                                        await axios.put(`http://localhost:3001/unblock/${u._id}`,{},{
                                        headers: { Authorization: `Bearer ${token}` }
                                        });
                                    } 
                                    else {
                                        await axios.put(`http://localhost:3001/block/${u._id}`,{},{
                                        headers: { Authorization: `Bearer ${token}` }
                                        });
                                    }
                                    getUsers();
                                }}>{u.isBlocked ? "unblock" : "block"}</button>
                                </center>
                            </td>
                    </tr>
                ))}
                 </table>
            </center>
           

        </>
    )
    
}
